def generate_role_assessment(
    role_name: str,
    curriculum_modules: list[str],
    approved_use_cases: list[str],
    restricted_use_cases: list[str],
    n_questions: int = 15,
) -> list[dict]:
    """Generate a role-specific assessment for Claude training certification."""
    prompt = f"""Generate a {n_questions}-question assessment for Claude training certification.
Role: {role_name}
Modules covered: {"; ".join(curriculum_modules)}
Approved use cases: {"; ".join(approved_use_cases)}
Restricted use cases: {"; ".join(restricted_use_cases)}

Assessment requirements:
- Mix question types: 8 multiple-choice, 4 scenario-based (longer stem), 3 true/false
- At least 4 questions must test the restricted use cases (knowing what NOT to do is critical)
- Scenarios should use realistic workplace situations for this role
- Pass mark: 80% (12/15)
- Each question: id, type, stem, options (list), correct_answer, explanation

Return JSON array of question objects only."""

    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=2500,
        messages=[{"role": "user", "content": prompt}],
    )
    return json.loads(resp.content[0].text)
